create database gym_fit;
use gym_fit;
DROP TABLE IF EXISTS fitness_data;

CREATE TABLE fitness_data (
    user_id INT,
    date DATE,
    name VARCHAR(50),
    age INT,
    weight FLOAT,
    calories_intake FLOAT,
    calories_burned FLOAT,
    steps INT,
    workout_type VARCHAR(50),
    workout_duration_min INT,
    clean_workout_type VARCHAR(50),
    gym_time VARCHAR(20),
    clean_gender VARCHAR(10),
    fix_trainer_name VARCHAR(50),
    calories_difference FLOAT,
    step_category VARCHAR(20),
    workout_duration VARCHAR(20)
);


select * from gym_fit limit 10;

